            "width": "100%",
            "align": "start"
          }
        ]
      },
      {
        "type": "ListViewItem",
        "children": [
          {
            "type": "Box",
            "direction": "row",
            "children": [
              {
                "type": "Col",
                "children": [
                  {
                    "type": "Title",
                    "value": "✅ 포함 사항",
                    "size": "md",
                    "weight": "bold"
                  },
                  {
                    "type": "Text",
                    "value": "• -차량 이용료 및 차량 운전비*1일8시간기준*（기준시간 이후 1시간이내까지는 지연추가금 서비스입니다.）\r\n-주차비\r\n-유류비\r\n-고속도로 통행료",
